  return decodeRefName(ref.replace(/^.*#\\/components\\/schemas\\//, \"\"))\n    }\n  }\n\n  getRefSchema =( model )=> {\n    let { specSelectors } = this.props\n\n    return specSelectors.findDefinition(model)\n  }\n\n  render () {\n    let { getComponent, getConfigs, specSelectors, schema, required, name, isRef, specPath, displayName,\n      includeReadOnly, includeWriteOnly} = this.props\n    const ObjectModel = getComponent(\"ObjectModel\")\n    const ArrayModel = getComponent(\"ArrayModel\")\n    const PrimitiveModel = getComponent(\"PrimitiveModel\")\n    let type = \"object\"\n    let $$ref = schema && schema.get(\"$$ref\")\n    let $ref = schema && schema.get(\"$ref\")\n\n    // If we weren't passed a `name` but have a resolved ref, grab the name from the ref\n    if (!name && $$ref) {\n      name = this.getModelName($$ref)\n    }\n\n    /*\n     * If we have an unresolved ref, get the schema and name from the ref.\n     * If the ref is external, we can't resolve it, so we just display the ref location.\n     * This is for situations where:\n     *  - the ref was not resolved by Swagger Client because we reached the traversal depth limit\n     *  - we had a circular ref inside the allOf keyword\n     */\n    if ($ref) {\n      const refName = this.getModelName($ref)\n      const refSchema = this.getRefSchema(refName)\n      if (Map.isMap(refSchema)) {\n        schema = refSchema.mergeDeep(schema)\n        if (!$$ref) {\n          schema = schema.set(\"$$ref\", $ref)\n          $$ref = $ref\n        }\n      } else if (Map.isMap(schema) && schema.size === 1) {\n        schema = null\n        name = $ref\n      }\n    }\n\n    if(!schema) {\n      return <span className=\"model model-title\">\n              <span className=\"model-title__text\">{ displayName || name }</span>\n              {!$ref && <RollingLoadSVG height=\"20px\" width=\"20px\" />}\n            </span>\n    }\n\n    const deprecated = specSelectors.isOAS3() && schema.get(\"deprecated\")\n    isRef = isRef !== undefined ? isRef : !!$$ref\n    type = schema && schema.get(\"type\") || type\n\n    switch(type) {\n      case \"object\":\n        return <ObjectModel\n          className=\"object\" { ...this.props }\n          specPath={specPath}\n          getConfigs={ getConfigs }\n          schema={ schema }\n          name={ name }\n          deprecated={deprecated}\n          isRef={ isRef }\n          includeReadOnly = {includeReadOnly}\n          includeWriteOnly = {includeWriteOnly}/>\n      case \"array\":\n        return <ArrayModel\n          className=\"array\" { ...this.props }\n          getConfigs={ getConfigs }\n          schema={ schema }\n          name={ name }\n          deprecated={deprecated}\n          required={ required }\n          includeReadOnly = {includeReadOnly}\n          includeWriteOnly = {includeWriteOnly}/>\n      case \"string\":\n      case \"number\":\n      case \"integer\":\n      case \"boolean\":\n      default:\n        return <PrimitiveModel\n          { ...this.props }\n          getComponent={ getComponent }\n          getConfigs={ getConfigs }\n          schema={ schema }\n          name={ name }\n          deprecated={deprecated}\n          required={ required }/>\n    }\n  }\n}\n","import React, { Component } from \"react\"\nimport Im, { Map } from \"immutable\"\nimport PropTypes from \"prop-types\"\n\n/* eslint-disable  react/jsx-no-bind */\n\nexport default class Models extends Component {\n  static propTypes = {\n    getComponent: PropTypes.func,\n    specSelectors: PropTypes.object,\n    specActions: PropTypes.object.isRequired,\n    layoutSelectors: PropTypes.object,\n    layoutActions: PropTypes.object,\n    getConfigs: PropTypes.func.isRequired\n  }\n\n  getSchemaBasePath = () => {\n    const isOAS3 = this.props.specSelectors.isOAS3()\n    return isOAS3 ? [\"components\", \"schemas\"] : [\"definitions\"]\n  }\n\n  getCollapsedContent = () => {\n    return \" \"\n  }\n\n  handleToggle = (name, isExpanded) => {\n    const { layoutActions } = this.props\n    layoutActions.show([...this.getSchemaBasePath(), name], isExpanded)\n    if(isExpanded) {\n      this.props.specActions.requestResolvedSubtree([...this.getSchemaBasePath(), name])\n    }\n  }\n\n  onLoadModels = (ref) => {\n    if (ref) {\n      this.props.layoutActions.readyToScroll(this.getSchemaBasePath(), ref)\n    }\n  }\n\n  onLoadModel = (ref) => {\n    if (ref) {\n      const name = ref.getAttribute(\"data-name\")\n      this.props.layoutActions.readyToScroll([...this.getSchemaBasePath(), name], ref)\n    }\n  }\n\n  render(){\n    let { specSelectors, getComponent, layoutSelectors, layoutActions, getConfigs } = this.props\n    let definitions = specSelectors.definitions()\n    let { docExpansion, defaultModelsExpandDepth } = getConfigs()\n    if (!definitions.size || defaultModelsExpandDepth < 0) return null\n\n    const specPathBase = this.getSchemaBasePath()\n    let showModels = layoutSelectors.isShown(specPathBase, defaultModelsExpandDepth > 0 && docExpansion !== \"none\")\n    const isOAS3 = specSelectors.isOAS3()\n\n    const ModelWrapper = getComponent(\"ModelWrapper\")\n    const Collapse = getComponent(\"Collapse\")\n    const ModelCollapse = getComponent(\"ModelCollapse\")\n    const JumpToPath = getComponent(\"JumpToPath\", true)\n    const ArrowUpIcon = getComponent(\"ArrowUpIcon\")\n    const ArrowDownIcon = getComponent(\"ArrowDownIcon\")\n\n    return <section className={ showModels ? \"models is-open\" : \"models\"} ref={this.onLoadModels}>\n      <h4>\n        <button\n          aria-expanded={showModels}\n          className=\"models-control\"\n          onClick={() => layoutActions.show(specPathBase, !showModels)}\n        >\n          <span>{isOAS3 ? \"Schemas\" : \"Models\"}</span>\n          {showModels ? <ArrowUpIcon /> : <ArrowDownIcon />}\n        </button>\n      </h4>\n      <Collapse isOpened={showModels}>\n        {\n          definitions.entrySeq().map(([name])=>{\n\n            const fullPath = [...specPathBase, name]\n            const specPath = Im.List(fullPath)\n\n            const schemaValue = specSelectors.specResolvedSubtree(fullPath)\n            const rawSchemaValue = specSelectors.specJson().getIn(fullPath)\n\n            const schema = Map.isMap(schemaValue) ? schemaValue : Im.Map()\n            const rawSchema = Map.isMap(rawSchemaValue) ? rawSchemaValue : Im.Map()\n\n            const displayName = schema.get(\"title\") || rawSchema.get(\"title\") || name\n            const isShown = layoutSelectors.isShown(fullPath, false)\n\n            if( isShown && (schema.size === 0 && rawSchema.size > 0) ) {\n              // Firing an action in a container render is not great,\n              // but it works for now.\n              this.props.specActions.requestResolvedSubtree(fullPath)\n            }\n\n            const content = <ModelWrapper name={ name }\n              expandDepth={ defaultModelsExpandDepth }\n              schema={ schema || Im.Map() }\n              displayName={displayName}\n              fullPath={fullPath}\n              specPath={specPath}\n              getComponent={ getComponent }\n              specSelectors={ specSelectors }\n              getConfigs = {getConfigs}\n              layoutSelectors = {layoutSelectors}\n              layoutActions = {layoutActions}\n              includeReadOnly = {true}\n              includeWriteOnly = {true}/>\n\n            const title = <span className=\"model-box\">\n              <span className=\"model model-title\">\n                {displayName}\n              </span>\n            </span>\n\n            return <div id={ `model-${name}` } className=\"model-container\" key={ `models-section-${name}` }\n                    data-name={name} ref={this.onLoadModel} >\n              <span className=\"models-jump-to-path\"><JumpToPath path={specPath} /></span>\n              <ModelCollapse\n                classes=\"model-box\"\n                collapsedContent={this.getCollapsedContent(name)}\n                onToggle={this.handleToggle}\n                title={title}\n                displayName={displayName}\n                modelName={name}\n                specPath={specPath}\n                layoutSelectors={layoutSelectors}\n                layoutActions={layoutActions}\n                hideSelfOnExpand={true}\n                expanded={ defaultModelsExpandDepth > 0 && isShown }\n                >{content}</ModelCollapse>\n              </div>\n          }).toArray()\n        }\n      </Collapse>\n    </section>\n  }\n}\n","import React from \"react\"\nimport ImPropTypes from \"react-immutable-proptypes\"\n\nconst EnumModel = ({ value, getComponent }) => {\n  let ModelCollapse = getComponent(\"ModelCollapse\")\n  let collapsedContent = <span>Array [ { value.count() } ]</span>\n  return <span className=\"prop-enum\">\n    Enum:<br />\n    <ModelCollapse collapsedContent={ collapsedContent }>\n      [ { value.map(String).join(\", \") } ]\n    </ModelCollapse>\n  </span>\n}\nEnumModel.propTypes = {\n  value: ImPropTypes.iterable,\n  getComponent: ImPropTypes.func\n}\n\nexport default EnumModel\n","export function isAbsoluteUrl(url) {\n  return url.match(/^(?:[a-z]+:)?\\/\\//i) // Matches http://, HTTP://, https://, ftp://, //example.com,\n}\n\nexport function addProtocol(url) {\n  if (!url.match(/^\\/\\//i)) return url // Checks if protocol is missing e.g. //example.com\n\n  return `${window.location.protocol}${url}`\n}\n\nexport function buildBaseUrl(selectedServer, specUrl) {\n  if (!selectedServer) return specUrl\n  if (isAbsoluteUrl(selectedServer)) return addProtocol(selectedServer)\n\n  return new URL(selectedServer, specUrl).href\n}\n\nexport function buildUrl(url, specUrl, { selectedServer=\"\" } = {}) {\n  if (!url) return undefined\n  if (isAbsoluteUrl(url)) return url\n\n  const baseUrl = buildBaseUrl(selectedServer, specUrl)\n  if (!isAbsoluteUrl(baseUrl)) {\n    return new URL(url, window.location.href).href\n  }\n  return new URL(url, baseUrl).href\n}\n\n/**\n * Safe version of buildUrl function. `selectedServer` can contain server variables\n * which can fail the URL resolution.\n */\nexport function safeBuildUrl(url, specUrl, { selectedServer=\"\" } = {}) {\n  try {\n    return buildUrl(url, specUrl, { selectedServer })\n  } catch {\n    return undefined\n  }\n}\n\nexport function sanitizeUrl(url) {\n  if (typeof url !== \"string\" || url.trim() === \"\") {\n    return \"\"\n  }\n\n  const urlTrimmed = url.trim()\n  const blankURL = \"about:blank\"\n\n  try {\n    const base = `https://base${String(Math.random()).slice(2)}`\n    const urlObject = new URL(urlTrimmed, base)\n    const scheme = urlObject.protocol.slice(0, -1)\n\n    // check for invalid schemes\n    if ([\"javascript\", \"data\", \"vbscript\"].includes(scheme.toLowerCase())) {\n      return blankURL\n    }\n\n    // return sanitized URI reference\n    if (urlObject.origin === base) {\n      return urlTrimmed.startsWith(\"/\")\n        ? `${urlObject.pathname}${urlObject.search}${urlObject.hash}`\n        : urlTrimmed.startsWith(\".\")\n        ? `.${urlObject.pathname}${urlObject.search}${urlObject.hash}`\n        : `${urlObject.pathname.substring(1)}${urlObject.search}${urlObject.hash}`\n    }\n\n    return String(urlObject)\n  } catch {\n    return blankURL\n  }\n}\n\n","/**\n * @prettier\n */\nimport React, { Component } from \"react\"\nimport PropTypes from \"prop-types\"\nimport { List } from \"immutable\"\nimport ImPropTypes from \"react-immutable-proptypes\"\nimport { sanitizeUrl } from \"core/utils/url\"\nimport classNames from \"classnames\"\nimport { getExtensions } from \"../../../utils\"\n\nconst braceOpen = \"{\"\nconst braceClose = \"}\"\nconst propClass = \"property\"\n\nexport default class ObjectModel extends Component {\n  static propTypes = {\n    schema: PropTypes.object.isRequired,\n    getComponent: PropTypes.func.isRequired,\n    getConfigs: PropTypes.func.isRequired,\n    expanded: PropTypes.bool,\n    onToggle: PropTypes.func,\n    specSelectors: PropTypes.object.isRequired,\n    name: PropTypes.string,\n    displayName: PropTypes.string,\n    isRef: PropTypes.bool,\n    expandDepth: PropTypes.number,\n    depth: PropTypes.number,\n    specPath: ImPropTypes.list.isRequired,\n    includeReadOnly: PropTypes.bool,\n    includeWriteOnly: PropTypes.bool,\n  }\n\n  render() {\n    let {\n      schema,\n      name,\n      displayName,\n      isRef,\n      getComponent,\n      getConfigs,\n      depth,\n      onToggle,\n      expanded,\n      specPath,\n      ...otherProps\n    } = this.props\n    let { specSelectors, expandDepth, includeReadOnly, includeWriteOnly } =\n      otherProps\n    const { isOAS3 } = specSelectors\n    const isEmbedded = depth > 2 || (depth === 2 && specPath.last() !== \"items\")\n\n    if (!schema) {\n      return null\n    }\n\n    const { showExtensions } = getConfigs()\n    const extensions = showExtensions ? getExtensions(schema) : List()\n\n    let description = schema.get(\"description\")\n    let properties = schema.get(\"properties\")\n    let additionalProperties = schema.get(\"additionalProperties\")\n    let title = schema.get(\"title\") || displayName || name\n    let requiredProperties = schema.get(\"required\")\n    let infoProperties = schema.filter(\n      (v, key) =>\n        [\"maxProperties\", \"minProperties\", \"nullable\", \"example\"].indexOf(\n          key\n        ) !== -1\n    )\n    let deprecated = schema.get(\"deprecated\")\n    let externalDocsUrl = schema.getIn([\"externalDocs\", \"url\"])\n    let externalDocsDescription = schema.getIn([\"externalDocs\", \"description\"])\n\n    const JumpToPath = getComponent(\"JumpToPath\", true)\n    const Markdown = getComponent(\"Markdown\", true)\n    const Model = getComponent(\"Model\")\n    const ModelCollapse = getComponent(\"ModelCollapse\")\n    const Property = getComponent(\"Property\")\n    const Link = getComponent(\"Link\")\n    const ModelExtensions = getComponent(\"ModelExtensions\")\n\n    const JumpToPathSection = () => {\n      return (\n        <span className=\"model-jump-to-path\">\n          <JumpToPath path={specPath} />\n        </span>\n      )\n    }\n    const collapsedContent = (\n      <span>\n        <span>{braceOpen}</span>...<span>{braceClose}</span>\n        {isRef ? <JumpToPathSection /> : \"\"}\n      </span>\n    )\n\n    const allOf = specSelectors.isOAS3() ? schema.get(\"allOf\") : null\n    const anyOf = specSelectors.isOAS3() ? schema.get(\"anyOf\") : null\n    const oneOf = specSelectors.isOAS3() ? schema.get(\"oneOf\") : null\n    const not = specSelectors.isOAS3() ? schema.get(\"not\") : null\n\n    const titleEl = title && (\n      <span className=\"model-title\">\n        {isRef && schema.get(\"$$ref\") && (\n          <span\n            className={classNames(\"model-hint\", {\n              \"model-hint--embedded\": isEmbedded,\n            })}\n          >\n            {schema.get(\"$$ref\")}\n          </span>\n        )}\n        <span className=\"model-title__text\">{title}</span>\n      </span>\n    )\n\n    return (\n      <span className=\"model\">\n        <ModelCollapse\n          modelName={name}\n          title={titleEl}\n          onToggle={onToggle}\n          expanded={expanded ? true : depth <= expandDepth}\n          collapsedContent={collapsedContent}\n        >\n          <span className=\"brace-open object\">{braceOpen}</span>\n          {!isRef ? null : <JumpToPathSection />}\n          <span className=\"inner-object\">\n            {\n              <table className=\"model\">\n                <tbody>\n                  {!description ? null : (\n                    <tr className=\"description\">\n                      <td>description:</td>\n                      <td>\n                        <Markdown source={description} />\n                      </td>\n                    </tr>\n                  )}\n                  {externalDocsUrl && (\n                    <tr className={\"external-docs\"}>\n                      <td>externalDocs:</td>\n                      <td>\n                        <Link\n                          target=\"_blank\"\n                          href={sanitizeUrl(externalDocsUrl)}\n                        >\n                          {externalDocsDescription || externalDocsUrl}\n                        </Link>\n                      </td>\n                    </tr>\n                  )}\n                  {!deprecated ? null : (\n                    <tr className={\"property\"}>\n                      <td>deprecated:</td>\n                      <td>true</td>\n                    </tr>\n                  )}\n                  {!(properties && properties.size)\n                    ? null\n                    : properties\n                        .entrySeq()\n                        .filter(([, value]) => {\n                          return (\n                            (!value.get(\"readOnly\") || includeReadOnly) &&\n                            (!value.get(\"writeOnly\") || includeWriteOnly)\n                          )\n                        })\n                        .map(([key, value]) => {\n                          let isDeprecated = isOAS3() && value.get(\"deprecated\")\n                          let isRequired =\n                            List.isList(requiredProperties) &&\n                            requiredProperties.contains(key)\n\n                          let classNames = [\"property-row\"]\n\n                          if (isDeprecated) {\n                            classNames.push(\"deprecated\")\n                          }\n\n                          if (isRequired) {\n                            classNames.push(\"required\")\n                          }\n\n                          return (\n                            <tr key={key} className={classNames.join(\" \")}>\n                              <td>\n                                {key}\n                                {isRequired && <span className=\"star\">*</span>}\n                              </td>\n                              <td>\n                                <Model\n                                  key={`object-${name}-${key}_${value}`}\n                                  {...otherProps}\n                                  required={isRequired}\n                                  getComponent={getComponent}\n                                  specPath={specPath.push(\"properties\", key)}\n                                  getConfigs={getConfigs}\n                                  schema={value}\n                                  depth={depth + 1}\n                                />\n                              </td>\n                            </tr>\n                          )\n                        })\n                        .toArray()}\n                  {extensions.size === 0 ? null : (\n                    <>\n                      <tr>\n                        <td>&nbsp;</td>\n                      </tr>\n                      <ModelExtensions\n                        extensions={extensions}\n                        propClass=\"extension\"\n                      />\n                    </>\n                  )}\n                  {!additionalProperties ||\n                  !additionalProperties.size ? null : (\n                    <tr>\n                      <td>{\"< * >:\"}</td>\n                      <td>\n                        <Model\n                          {...otherProps}\n                          required={false}\n                          getComponent={getComponent}\n                          specPath={specPath.push(\"additionalProperties\")}\n                          getConfigs={getConfigs}\n                          schema={additionalProperties}\n                          depth={depth + 1}\n                        />\n                      </td>\n                    </tr>\n                  )}\n                  {!allOf ? null : (\n                    <tr>\n                      <td>{\"allOf ->\"}</td>\n                      <td>\n                        {allOf.map((schema, k) => {\n                          return (\n                            <div key={k}>\n                              <Model\n                                {...otherProps}\n                                required={false}\n                                getComponent={getComponent}\n                                specPath={specPath.push(\"allOf\", k)}\n                                getConfigs={getConfigs}\n                                schema={schema}\n                                depth={depth + 1}\n                              />\n                            </div>\n                          )\n                        })}\n                      </td>\n                    </tr>\n                  )}\n                  {!anyOf ? null : (\n                    <tr>\n                      <td>{\"anyOf ->\"}</td>\n                      <td>\n                        {anyOf.map((schema, k) => {\n                          return (\n                            <div key={k}>\n                              <Model\n                                {...otherProps}\n                                required={false}\n                                getComponent={getComponent}\n                                specPath={specPath.push(\"anyOf\", k)}\n                                getConfigs={getConfigs}\n                                schema={schema}\n                                depth={depth + 1}\n                              />\n                            </div>\n                          )\n                        })}\n                      </td>\n                    </tr>\n                  )}\n                  {!oneOf ? null : (\n                    <tr>\n                      <td>{\"oneOf ->\"}</td>\n                      <td>\n                        {oneOf.map((schema, k) => {\n                          return (\n                            <div key={k}>\n                              <Model\n                                {...otherProps}\n                                required={false}\n                                getComponent={getComponent}\n                                specPath={specPath.push(\"oneOf\", k)}\n                                getConfigs={getConfigs}\n                                schema={schema}\n                                depth={depth + 1}\n                              />\n                            </div>\n                          )\n                        })}\n                      </td>\n                    </tr>\n                  )}\n                  {!not ? null : (\n                    <tr>\n                      <td>{\"not ->\"}</td>\n                      <td>\n                        <div>\n                          <Model\n                            {...otherProps}\n                            required={false}\n                            getComponent={getComponent}\n                            specPath={specPath.push(\"not\")}\n                            getConfigs={getConfigs}\n                            schema={not}\n                            depth={depth + 1}\n                          />\n                        </div>\n                      </td>\n                    </tr>\n                  )}\n                </tbody>\n              </table>\n            }\n          </span>\n          <span className=\"brace-close\">{braceClose}</span>\n        </ModelCollapse>\n        {infoProperties.size\n          ? infoProperties\n              .entrySeq()\n              .map(([key, v]) => (\n                <Property\n                  key={`${key}-${v}`}\n                  propKey={key}\n                  propVal={v}\n                  propClass={propClass}\n                />\n              ))\n          : null}\n      </span>\n    )\n  }\n}\n","import React, { Component } from \"react\"\nimport PropTypes from \"prop-types\"\nimport ImPropTypes from \"react-immutable-proptypes\"\nimport { sanitizeUrl } from \"core/utils/url\"\n\nconst propClass = \"property\"\n\nexport default class ArrayModel extends Component {\n  static propTypes = {\n    schema: PropTypes.object.isRequired,\n    getComponent: PropTypes.func.isRequired,\n    getConfigs: PropTypes.func.isRequired,\n    specSelectors: PropTypes.object.isRequired,\n    name: PropTypes.string,\n    displayName: PropTypes.string,\n    required: PropTypes.bool,\n    expandDepth: PropTypes.number,\n    specPath: ImPropTypes.list.isRequired,\n    depth: PropTypes.number,\n    includeReadOnly: PropTypes.bool,\n    includeWriteOnly: PropTypes.bool,\n  }\n\n  render(){\n    let { getComponent, getConfigs, schema, depth, expandDepth, name, displayName, specPath } = this.props\n    let description = schema.get(\"description\")\n    let items = schema.get(\"items\")\n    let title = schema.get(\"title\") || displayName || name\n    let properties = schema.filter( ( v, key) => [\"type\", \"items\", \"description\", \"$$ref\", \"externalDocs\"].indexOf(key) === -1 )\n    let externalDocsUrl = schema.getIn([\"externalDocs\", \"url\"])\n    let externalDocsDescription = schema.getIn([\"externalDocs\", \"description\"])\n\n\n    const Markdown = getComponent(\"Markdown\", true)\n    const ModelCollapse = getComponent(\"ModelCollapse\")\n    const Model = getComponent(\"Model\")\n    const Property = getComponent(\"Property\")\n    const Link = getComponent(\"Link\")\n\n    const titleEl = title &&\n      <span className=\"model-title\">\n        <span className=\"model-title__text\">{ title }</span>\n      </span>\n\n    /*\n    Note: we set `name={null}` in <Model> below because we don't want\n    the name of the current Model passed (and displayed) as the name of the array element Model\n    */\n\n    return <span className=\"model\">\n      <ModelCollapse title={titleEl} expanded={ depth <= expandDepth } collapsedContent=\"[...]\">\n        [\n          {\n            properties.size ? properties.entrySeq().map( ( [ key, v ] ) => <Property key={`${key}-${v}`} propKey={ key } propVal={ v } propClass={ propClass } />) : null\n          }\n          {\n            !description ? (properties.size ? <div className=\"markdown\"></div> : null) :\n              <Markdown source={ description } />\n          }\n          { externalDocsUrl &&\n            <div className=\"external-docs\">\n               <Link target=\"_blank\" href={sanitizeUrl(externalDocsUrl)}>{externalDocsDescription || externalDocsUrl}</Link>\n             </div>\n          }\n          <span>\n            <Model\n              { ...this.props }\n              getConfigs={ getConfigs }\n              specPath={specPath.push(\"items\")}\n              name={null}\n              schema={ items }\n              required={ false }\n              depth={ depth + 1 }\n            />\n          </span>\n        ]\n      </ModelCollapse>\n    </span>\n  }\n}\n","/**\n * @prettier\n */\nimport React, { Component } from \"react\"\nimport PropTypes from \"prop-types\"\nimport { getExtensions } from \"core/utils\"\nimport { sanitizeUrl } from \"core/utils/url\"\n\nconst propClass = \"property primitive\"\n\nexport default class Primitive extends Component {\n  static propTypes = {\n    schema: PropTypes.object.isRequired,\n    getComponent: PropTypes.func.isRequired,\n    getConfigs: PropTypes.func.isRequired,\n    name: PropTypes.string,\n    displayName: PropTypes.string,\n    depth: PropTypes.number,\n    expandDepth: PropTypes.number,\n  }\n\n  render() {\n    let {\n      schema,\n      getComponent,\n      getConfigs,\n      name,\n      displayName,\n      depth,\n      expandDepth,\n    } = this.props\n\n    const { showExtensions } = getConfigs()\n\n    if (!schema || !schema.get) {\n      // don't render if schema isn't correctly formed\n      return <div></div>\n    }\n\n    let type = schema.get(\"type\")\n    let format = schema.get(\"format\")\n    let xml = schema.get(\"xml\")\n    let enumArray = schema.get(\"enum\")\n    let title = schema.get(\"title\") || displayName || name\n    let description = schema.get(\"description\")\n    const extensions = getExtensions(schema)\n\n    let properties = schema\n      .filter(\n        (_, key) =>\n          [\n            \"enum\",\n            \"type\",\n            \"format\",\n            \"description\",\n            \"$$ref\",\n            \"externalDocs\",\n          ].indexOf(key) === -1\n      )\n      .filterNot((_, key) => extensions.has(key))\n    let externalDocsUrl = schema.getIn([\"externalDocs\", \"url\"])\n    let externalDocsDescription = schema.getIn([\"externalDocs\", \"description\"])\n\n    const Markdown = getComponent(\"Markdown\", true)\n    const EnumModel = getComponent(\"EnumModel\")\n    const Property = getComponent(\"Property\")\n    const ModelCollapse = getComponent(\"ModelCollapse\")\n    const Link = getComponent(\"Link\")\n    const ModelExtensions = getComponent(\"ModelExtensions\")\n\n    const titleEl = title && (\n      <span className=\"model-title\">\n        <span className=\"model-title__text\">{title}</span>\n      </span>\n    )\n\n    return (\n      <span className=\"model\">\n        <ModelCollapse\n          title={titleEl}\n          expanded={depth <= expandDepth}\n          collapsedContent=\"[...]\"\n        >\n          <span className=\"prop\">\n            {name && depth > 1 && <span className=\"prop-name\">{title}</span>}\n            <span className=\"prop-type\">{type}</span>\n            {format && <span className=\"prop-format\">(${format})</span>}\n            {properties.size\n              ? properties\n                  .entrySeq()\n                  .map(([key, v]) => (\n                    <Property\n                      key={`${key}-${v}`}\n                      propKey={key}\n                      propVal={v}\n                      propClass={propClass}\n                    />\n                  ))\n              : null}\n            {showExtensions && extensions.size > 0 ? (\n              <ModelExtensions\n                extensions={extensions}\n                propClass={`${propClass} extension`}\n              />\n            ) : null}\n            {!descriptio